import{_ as a,o,c as t,a2 as r}from"./chunks/framework.DTu5Mxym.js";const h=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":1782453500000}'),i={name:"release-notes.md"};function n(d,e,s,l,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="_0-53-0-development" tabindex="-1">0.53.0 (development) <a class="header-anchor" href="#_0-53-0-development" aria-label="Permalink to &quot;0.53.0 (development)&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong><code>pyworkforce.queuing.ErlangA</code></strong> — a new M/M/c+M queue model with customer <strong>abandonment</strong> (patience). Exposes <code>waiting_probability</code>, <code>abandonment_probability</code>, <code>achieved_occupancy</code>, <code>average_speed_of_answer</code>, <code>average_queue_length</code>, an exact <code>service_level</code>, and <code>required_positions</code> with service-level, occupancy and abandonment targets. All metrics are computed exactly from the birth-death stationary distribution and verified against a Monte Carlo simulation and the Erlang C patient limit.</li><li><strong><code>pyworkforce.queuing.MultiErlangA</code></strong> — the abandonment-aware counterpart of <code>MultiErlangC</code>: evaluates <code>ErlangA</code> over a parameter grid in parallel.</li><li><strong><code>pyworkforce.shifts</code></strong> — builders to create <code>shifts_coverage</code> definitions without hand-writing 0/1 arrays: <code>shift_coverage_from_hours</code>, <code>shift_coverage_from_spans</code>, <code>shift_coverage_from_periods</code>, plus <code>validate_shift_coverage</code> and <code>coverage_to_dataframe</code>.</li><li><strong><code>pyworkforce.utils.results_to_dataframe</code></strong> — turn <code>Multi*</code> results (and the parameters that produced them) into a tidy <code>pandas.DataFrame</code>.</li><li>All estimators now provide <code>get_params()</code> and a readable <code>repr()</code> (<code>BaseWorkforce</code> mixin), and store their last result as <code>solution_</code>.</li></ul><h3 id="bug-fixes" tabindex="-1">Bug fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug fixes&quot;">​</a></h3><ul><li><strong><code>MultiErlangC</code></strong> now correctly populates <code>achieved_occupancy_params</code> and <code>required_positions_params</code> (previously always <code>None</code>).</li><li>Validation helpers no longer reject integers where a float is expected (for example <code>max_search_time=240</code>) and now reject booleans, <code>NaN</code> and infinities.</li><li><code>MinHoursRoster</code> rejects duplicate resource names, which previously caused silent index-lookup errors for banned shifts and preferences.</li></ul><h3 id="api-quality" tabindex="-1">API quality <a class="header-anchor" href="#api-quality" aria-label="Permalink to &quot;API quality&quot;">​</a></h3><ul><li>Schedulers and <code>MinHoursRoster</code> validate their inputs and shapes up front with clear, consistent <code>ValueError</code> / <code>KeyError</code> messages.</li><li>Greatly expanded test suite (35 → 120+ tests) and higher coverage.</li></ul><h3 id="packaging-tooling" tabindex="-1">Packaging &amp; tooling <a class="header-anchor" href="#packaging-tooling" aria-label="Permalink to &quot;Packaging &amp; tooling&quot;">​</a></h3><ul><li>Migrated packaging from <code>setup.py</code> to a PEP 621 <strong><code>pyproject.toml</code></strong>.</li><li>Upgraded dependency floors (<code>numpy&gt;=2.0</code>, <code>pandas&gt;=2.2</code>, <code>ortools&gt;=9.14</code>, <code>joblib&gt;=1.4.2</code>); development extras are now installed with <code>pip install -e &quot;.[dev]&quot;</code>.</li><li>Added <a href="https://docs.astral.sh/ruff/" target="_blank" rel="noreferrer">ruff</a> linting, enforced in CI.</li><li>CI now runs a lint gate, cancels superseded runs, and tests against the latest dependencies. Added a Dependabot config and a PyPI trusted-publishing release workflow.</li></ul><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><ul><li>Estimator constructors no longer silently accept unknown keyword arguments, so typos in parameter names now raise a clear <code>TypeError</code>.</li></ul><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Documentation moved from Read the Docs / Sphinx to a <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> site published on <strong>GitHub Pages</strong>.</li><li>Added self-contained, notebook-style tutorials with real outputs: an end-to-end queue → schedule → roster walkthrough and a scenario-comparison guide using the grid estimators and <code>results_to_dataframe</code>.</li></ul><h2 id="_0-5-2" tabindex="-1">0.5.2 <a class="header-anchor" href="#_0-5-2" aria-label="Permalink to &quot;0.5.2&quot;">​</a></h2><ul><li>Latest Python support (3.12–3.14) and CI / packaging updates.</li></ul><p>For older releases, see the <a href="https://github.com/rodrigo-arenas/pyworkforce/releases" target="_blank" rel="noreferrer">GitHub releases page</a>.</p>',17)])])}const g=a(i,[["render",n]]);export{h as __pageData,g as default};
